mapper.select:
SELECT COUNT(*) FROM out_store t1,product t2
WHERE t1.product_id = t2.product_id

  AND t1.store_id = #{storeId}


  AND t2.product_name like concat('%',#{productName},'%')


  AND t1.is_out = #{isOut}


  AND t1.create_time >=${startTime}


  AND t1.create_time <=${endTime}

SELECT t1.*,t2.product_name,t3.store_name,t4.user_code
FROM out_store t1,product t2,store t3,user_info t4
WHERE t1.product_id = t2.product_id
AND t1.store_id =t3.store_id
AND t1.create_by = t4.user_id

  AND t1.store_id = #{outStore.storeId}


  AND t2.product_name like concat('%',#{outStore.productName},'%')


  AND t1.is_out = #{outStore.isOut}


  AND t1.create_time >=${outStore.startTime}


  AND t1.create_time <=${outStore.endTime}

order by t1.create_time desc
limit #{page.limitIndex},#{page.pageSize}

SELECT DISTINCT user_code FROM user_info t1,out_store t2
where t2.tally_id = #{tallId}
AND t1.user_id = t2.tally_id
